+  test("action tools have return_screenshot parameter", () => {
+    const adapter = new WebAdapter();
+    const tools = adapter.toolDefinitions();
+    const toolsWithReturnScreenshot = ["click", "type", "press", "navigate", "eval", "wait_for"];
